#!/usr/bin/env bash
set -euo pipefail

# Generated by npm run wgs:query-readiness.
# Usage:
#   ./output/wgs-local-setup-plan.sh summary
#   ./output/wgs-local-setup-plan.sh check-inputs
#   ./output/wgs-local-setup-plan.sh pull-containers
#   ./output/wgs-local-setup-plan.sh print-plan

phase="${1:-summary}"

case "$phase" in
  summary)
    cat <<'SUMMARY'
Difficulty: hard
Runnable now: false
Active setup hours: 4-12
Wall-clock hours: 24-96
Recommended environment: Docker-capable linux/amd64 environment or equivalent, 16+ CPU threads, 64GB+ RAM, and 500GB+ free disk for HG002 BAM/CRAM, reference, caller intermediates, and benchmark outputs.

Missing inputs:
  - HG002 BAM/CRAM
  - matching reference FASTA
  - read-count intervals
  - trained cohort model for gCNV best performance
  - repeat-specification catalog

Native setup hints:
  - GATK-SV: Install Cromwell and set GATK_SV_WDL_DIR to a local GATK-SV WDL checkout; this is not satisfied by plain GATK alone.

Environment variables expected by check-inputs:
  - HG002_BAM_OR_CRAM
  - HG002_REFERENCE_FASTA
  - WGS_READCOUNT_INTERVALS
  - GATK_GCNV_MODEL_DIR
  - GATK_SV_WDL_DIR
  - WGS_REPEAT_CATALOG
SUMMARY
    ;;
  check-inputs)
    missing=0
if [[ -z "${HG002_BAM_OR_CRAM:-}" || ! -e "${HG002_BAM_OR_CRAM}" ]]; then
  echo "missing HG002_BAM_OR_CRAM: set it to an existing local path" >&2
  missing=1
fi
if [[ -z "${HG002_REFERENCE_FASTA:-}" || ! -e "${HG002_REFERENCE_FASTA}" ]]; then
  echo "missing HG002_REFERENCE_FASTA: set it to an existing local path" >&2
  missing=1
fi
if [[ -z "${WGS_READCOUNT_INTERVALS:-}" || ! -e "${WGS_READCOUNT_INTERVALS}" ]]; then
  echo "missing WGS_READCOUNT_INTERVALS: set it to an existing local path" >&2
  missing=1
fi
if [[ -z "${GATK_GCNV_MODEL_DIR:-}" || ! -e "${GATK_GCNV_MODEL_DIR}" ]]; then
  echo "missing GATK_GCNV_MODEL_DIR: set it to an existing local path" >&2
  missing=1
fi
if [[ -z "${GATK_SV_WDL_DIR:-}" || ! -e "${GATK_SV_WDL_DIR}" ]]; then
  echo "missing GATK_SV_WDL_DIR: set it to an existing local path" >&2
  missing=1
fi
if [[ -z "${WGS_REPEAT_CATALOG:-}" || ! -e "${WGS_REPEAT_CATALOG}" ]]; then
  echo "missing WGS_REPEAT_CATALOG: set it to an existing local path" >&2
  missing=1
fi
    if [[ "$missing" -ne 0 ]]; then
      exit 1
    fi
    echo "All configured WGS input paths exist."
    ;;
  pull-containers)
docker pull --platform linux/amd64 quay.io/biocontainers/manta:1.6.0--h9ee0642_2
docker pull --platform linux/amd64 broadinstitute/gatk:latest
docker pull --platform linux/amd64 ensemblorg/ensembl-vep:release_112.0
docker pull --platform linux/amd64 quay.io/biocontainers/expansionhunter:5.0.0--h9ee0642_0
docker pull --platform linux/amd64 adamgiess/truvari:5.3.0
docker pull --platform linux/amd64 quay.io/biocontainers/hap.py:0.3.15--py27hcb73b3d_0
    ;;
  print-plan)
    cat <<'PLAN'
# Setup commands
mkdir -p 'vendor/health-analysis-skill/output/external-validation'
Install required tools where `run_plan.required_tools[].available` is false before running the caller commands.

# Caller container pulls
docker pull --platform linux/amd64 quay.io/biocontainers/manta:1.6.0--h9ee0642_2
docker pull --platform linux/amd64 broadinstitute/gatk:latest
docker pull --platform linux/amd64 ensemblorg/ensembl-vep:release_112.0
docker pull --platform linux/amd64 quay.io/biocontainers/expansionhunter:5.0.0--h9ee0642_0

# Benchmark container pulls
docker pull --platform linux/amd64 adamgiess/truvari:5.3.0
docker pull --platform linux/amd64 quay.io/biocontainers/hap.py:0.3.15--py27hcb73b3d_0

# Query generation commands
configManta.py --bam "${HG002_BAM_OR_CRAM}" --referenceFasta "${HG002_REFERENCE_FASTA}" --runDir 'vendor/health-analysis-skill/output/external-validation/giab_hg002_sv_v0_6_grch37-manta' && 'vendor/health-analysis-skill/output/external-validation/giab_hg002_sv_v0_6_grch37-manta/runWorkflow.py' && cp 'vendor/health-analysis-skill/output/external-validation/giab_hg002_sv_v0_6_grch37-manta/results/variants/diploidSV.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.vcf.gz'
gatk CollectReadCounts -I "${HG002_BAM_OR_CRAM}" -R "${HG002_REFERENCE_FASTA}" -L "${WGS_READCOUNT_INTERVALS}" --interval-merging-rule OVERLAPPING_ONLY -O 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.counts.hdf5' && gatk GermlineCNVCaller --run-mode CASE --contig-ploidy-calls "${GATK_GCNV_MODEL_DIR}" --model "${GATK_GCNV_MODEL_DIR}" --input 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.counts.hdf5' --output 'vendor/health-analysis-skill/output/external-validation/giab_hg002_sv_v0_6_grch37-gcnv' --output-prefix 'giab_hg002_sv_v0_6_grch37' # then convert genotyped segments to 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.vcf.gz'
# Run GATK-SV WDL modules with Cromwell/Terra using "${HG002_BAM_OR_CRAM}" and "${HG002_REFERENCE_FASTA}", then export the genotyped SV VCF to 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.vcf.gz'
gatk HaplotypeCaller -R "${HG002_REFERENCE_FASTA}" -I "${HG002_BAM_OR_CRAM}" -O 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.g.vcf.gz' && gatk GenotypeGVCFs -R "${HG002_REFERENCE_FASTA}" -V 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.g.vcf.gz' -O 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.vcf.gz'
ExpansionHunter --reads "${HG002_BAM_OR_CRAM}" --reference "${HG002_REFERENCE_FASTA}" --variant-catalog "${WGS_REPEAT_CATALOG}" --output-prefix 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query' && bgzip -c 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.vcf' > 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.vcf.gz'

# Postprocess commands
bcftools sort -Oz -o 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.sorted.tmp.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.vcf.gz' && mv 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.sorted.tmp.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.vcf.gz'
bcftools index -t 'vendor/health-analysis-skill/output/external-validation/hg002-sv-query.vcf.gz'
vep --cache --offline --everything --vcf -i 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.vcf.gz' -o 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.vep.vcf'
bcftools sort -Oz -o 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.sorted.tmp.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.vcf.gz' && mv 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.sorted.tmp.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.vcf.gz'
bcftools index -t 'vendor/health-analysis-skill/output/external-validation/hg002-small-variant-query.vcf.gz'
bcftools sort -Oz -o 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.sorted.tmp.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.vcf.gz' && mv 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.sorted.tmp.vcf.gz' 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.vcf.gz'
bcftools index -t 'vendor/health-analysis-skill/output/external-validation/hg002-repeat-query.vcf.gz'

# Validation commands
npm run wgs:external-validation -- --run # scores giab_hg002_sv_v0_6_grch37 once truth/query inputs, indexes, and benchmark tools are present
docker run --rm --platform linux/amd64 -v "$(cd ../.. && pwd)":/work -w /work/skills/longevity-analysis adamgiess/truvari:5.3.0 truvari bench -b '../../external-truthsets/giab/HG002_SVs_Tier1_v0.6.vcf.gz' -c 'output/external-validation/hg002-sv-query.vcf.gz' --includebed '../../external-truthsets/giab/HG002_SVs_Tier1_v0.6.bed' -o 'output/external-validation/giab-hg002-sv-truvari-summary'
npm run wgs:external-validation -- --run # scores giab_hg002_small_variant_grch38 once truth/query inputs, indexes, and benchmark tools are present
docker run --rm --platform linux/amd64 -v "$(cd ../.. && pwd)":/work -w /work/skills/longevity-analysis quay.io/biocontainers/hap.py:0.3.15--py27hcb73b3d_0 hap.py '../../external-truthsets/giab/HG002_GRCh38_1_22_v4.2.1_benchmark.vcf.gz' 'output/external-validation/hg002-small-variant-query.vcf.gz' -f '../../external-truthsets/giab/HG002_GRCh38_1_22_v4.2.1_benchmark_noinconsistent.bed' -o 'output/external-validation/giab-hg002-small-happy-summary'
npm run wgs:external-validation -- --run # scores giab_hg002_repeat_regions_grch38 once truth/query inputs, indexes, and benchmark tools are present
docker run --rm --platform linux/amd64 -v "$(cd ../.. && pwd)":/work -w /work/skills/longevity-analysis adamgiess/truvari:5.3.0 truvari bench -b '../../external-truthsets/giab/HG002_GRCh38_TandemRepeats_v1.0.1.vcf.gz' -c 'output/external-validation/hg002-repeat-query.vcf.gz' --includebed '../../external-truthsets/giab/HG002_GRCh38_TandemRepeats_v1.0.1_Tier1.bed.gz' -o 'output/external-validation/giab-hg002-repeat-truvari-summary'
PLAN
    ;;
  *)
    echo "Unknown phase: $phase" >&2
    echo "Expected one of: summary, check-inputs, pull-containers, print-plan" >&2
    exit 2
    ;;
esac
